mapper.select:
SELECT cwi.合同危废明细编号, cwi.合同条目编号, cwi.报价危废明细编号, cwi.危废条目编号, hwc.废物类别, hwi.行业来源, hwi.废物代码, hwi.危险特性, cwi.废物名称, cwi.废物形态, cwi.计量单位, cwi.计划转移数量, cwi.是否启用辅助核算, cwi.辅助计量单位, cwi.辅助单位每基础单位数量, cwi.辅助数量, cwi.辅助单价, cwi.单价, cwi.金额, cwi.付款方, cwi.计价方案, cwi.低价备注, cwi.创建时间, cwi.更新时间 FROM CONTRACT_WASTE_ITEM cwi LEFT JOIN HAZARDOUS_WASTE_ITEM hwi ON cwi.危废条目编号 = hwi.条目编号 LEFT JOIN HAZARDOUS_WASTE_CATEGORY hwc ON hwi.废物类别编号 = hwc.废物类别编号 WHERE cwi.合同条目编号 IN
#{itemId}
ORDER BY cwi.合同条目编号 ASC, cwi.创建时间 ASC

mapper.delete:
DELETE FROM CONTRACT_WASTE_ITEM
WHERE 合同条目编号 IN

    #{itemId}

mapper.select:
SELECT ci.合同条目编号 as contractItemId, COALESCE(cwi.付款方, ci.付款方) as payer FROM CONTRACT_ITEM ci LEFT JOIN CONTRACT_WASTE_ITEM cwi ON ci.合同条目编号 = cwi.合同条目编号 WHERE ci.合同条目编号 IN
#{itemId}
GROUP BY ci.合同条目编号, COALESCE(cwi.付款方, ci.付款方) ORDER BY ci.合同条目编号 ASC
